// ── Contact form for brands ───────────────────────────────────────────────────
type FormState = {
  name: string;
  email: string;
  company: string;
  type: string;
  message: string;
};

function BrandContactForm() {
  const [form, setForm] = useState<FormState>({
    name: "",
    email: "",
    company: "",
    type: "",
    message: "",
  });
  const [status, setStatus] = useState<"idle" | "sending" | "sent" | "error">("idle");

  function handleChange(field: keyof FormState, value: string) {
    setForm((f) => ({ ...f, [field]: value }));
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!form.name || !form.email || !form.message) return;
    setStatus("sending");
    try {
      const res = await fetch(FORMSPREE, {
        method: "POST",
        headers: { "Content-Type": "application/json", Accept: "application/json" },
        body: JSON.stringify({ ...form, _subject: `Colaboración TechByFlo — ${form.type || "General"}` }),
      });
      if (res.ok) {
        setStatus("sent");
      } else {
        setStatus("error");
      }
    } catch {
      setStatus("error");
    }
  }

  if (status === "sent") {
    return (
      <div className="glass-card rounded-2xl p-6 flex flex-col items-center gap-3 text-center border border-green-500/30 bg-green-500/5">
        <CheckCircle className="w-10 h-10 text-green-400" />
        <h3 className="font-black text-white text-lg">¡Mensaje recibido!</h3>
        <p className="text-slate-400 text-sm">
          Te respondo en menos de 24 horas. Revisa también tu carpeta de spam.
        </p>
      </div>
    );
  }

  const inputClass =
    "w-full px-4 py-3 bg-slate-800/60 border border-slate-700 rounded-xl text-white placeholder-slate-500 text-sm focus:outline-none focus:border-[#FFD400]/50 transition-colors";

  return (
    <form onSubmit={handleSubmit} className="space-y-3">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
        <input
          required
          type="text"
          placeholder="Tu nombre *"
          value={form.name}
          onChange={(e) => handleChange("name", e.target.value)}
          className={inputClass}
        />
        <input
          required
          type="email"
          placeholder="Tu email *"
          value={form.email}
          onChange={(e) => handleChange("email", e.target.value)}
          className={inputClass}
        />
      </div>
      <input
        type="text"
        placeholder="Empresa o proyecto"
        value={form.company}
        onChange={(e) => handleChange("company", e.target.value)}
        className={inputClass}
      />
      <select
        value={form.type}
        onChange={(e) => handleChange("type", e.target.value)}
        className={cn(inputClass, !form.type && "text-slate-500")}
      >
        <option value="" disabled>Tipo de colaboración</option>
        <option value="Escudo Digital Autónomo">Escudo Digital Autónomo</option>
        <option value="Escudo Digital Autónomo Pro">Escudo Digital Autónomo Pro</option>
        <option value="Taller Anti-Phishing">Taller Anti-Phishing</option>
        <option value="Auditoría Pyme">Auditoría Pyme</option>
        <option value="Programa anual">Programa anual</option>
        <option value="Digital Guard Ejecutivo">Digital Guard Ejecutivo</option>
        <option value="Otro">Otro</option>
      </select>
      <textarea
        required
        rows={4}
        placeholder="Cuéntame en qué puedo ayudarte *"
        value={form.message}
        onChange={(e) => handleChange("message", e.target.value)}
        className={cn(inputClass, "resize-none")}
      />
      {status === "error" && (
        <p className="text-red-400 text-xs pl-1">
          Algo salió mal. Escríbeme directamente en Instagram @techbyflo.
        </p>
      )}
      <button
        type="submit"
        disabled={status === "sending"}
        className={cn(
          "cta-shimmer w-full py-3.5 rounded-xl font-black text-sm flex items-center justify-center gap-2 transition-all",
          status === "sending"
            ? "bg-slate-700 text-slate-400 cursor-not-allowed"
            : "bg-[#FFD400] text-[#0F2438] hover:bg-[#FFE033] shadow-lg"
        )}
      >
        {status === "sending" ? (
          "Enviando…"
        ) : (
