          <p className="text-slate-400 text-sm leading-relaxed">
            Empieza con una auditoría gratuita. Sin compromiso. Ves tus vulnerabilidades reales en 20-30 min.
          </p>
        </div>

        {/* Audience selector tabs */}
        <div className="inline-flex gap-1 p-1 bg-slate-800/60 rounded-xl border border-slate-700">
          <button
            onClick={() => setAudience("individual")}
            className={cn(
              "px-4 py-2 rounded-lg text-sm font-bold transition-all duration-200",
              audience === "individual"
                ? "bg-[#FFD400] text-[#0F2438]"
                : "text-slate-400 hover:text-white"
            )}
          >
            Para ti
          </button>
          <button
            onClick={() => setAudience("marca")}
            className={cn(
              "px-4 py-2 rounded-lg text-sm font-bold transition-all duration-200 flex items-center gap-1.5",
              audience === "marca"
                ? "bg-[#FFD400] text-[#0F2438]"
                : "text-slate-400 hover:text-white"
            )}
          >
            <Building2 className="w-3.5 h-3.5" />
            Para marcas
          </button>
        </div>
      </div>

      {/* ── STORY — Quién es Flo ── */}
      <section className="w-full mb-8">
        <div className="glass-card rounded-2xl p-5 border border-slate-700/50 space-y-4">
          <div className="flex items-start gap-4">
            <div className="relative shrink-0">
              <img
                src="/logo.svg"
                alt="TechByFlo"
                className="w-14 h-14 rounded-full border-2 border-[#FFD400]/40 object-cover"
              />
              <span className="absolute -bottom-0.5 -right-0.5 w-4 h-4 bg-green-500 rounded-full border-2 border-[#0F2438]" />
            </div>
            <div>
              <p className="font-black text-white text-sm">Hola, soy Flo 👋</p>
              <p className="text-slate-400 text-xs leading-relaxed mt-1">
                Llevo años ayudando a autónomos y pequeñas empresas a blindar su seguridad digital
                sin tecnicismos, sin humo y en español.
              </p>
            </div>
          </div>
          <p className="text-slate-300 text-sm leading-relaxed">
            No soy consultor de traje. Soy el tío que{" "}
            <span className="text-white font-semibold">te lo explica de verdad</span>:
            qué hacer, en qué orden, y por qué. Con +10K personas que me siguen en TikTok e
            Instagram, he aprendido exactamente qué dudas tiene la gente normal sobre seguridad digital.
          </p>
          <div className="grid grid-cols-3 gap-3 pt-1">
            {[
              { value: "+10K", label: "seguidores" },
              { value: "+200", label: "publicaciones" },
              { value: "7+ años", label: "experiencia" },
            ].map(({ value, label }) => (
              <div key={label} className="text-center p-3 bg-slate-800/60 rounded-xl border border-slate-700/50">
                <p className="text-xl font-black text-[#FFD400]">{value}</p>
                <p className="text-[10px] text-slate-500 mt-0.5">{label}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── DOLOR — ¿Te suena familiar? ── */}
      <section className="space-y-4 mb-10">
        <div className="text-center space-y-1">
          <p className="text-xs text-slate-500 uppercase tracking-widest font-semibold">El problema</p>
          <h2 className="text-lg font-black text-white">¿Te suena familiar?</h2>
        </div>

        <div className="space-y-3">
          {pains.map((pain, i) => (
            <div
              key={i}
              className="glass-card rounded-xl p-4 border border-slate-700/50 flex items-start gap-3 hover:border-slate-600 transition-colors"
            >
              <span className="text-2xl shrink-0 mt-0.5">{pain.emoji}</span>
              <div>
                <p className="font-bold text-sm text-white leading-snug">{pain.title}</p>
                <p className="text-xs text-slate-400 mt-1 leading-relaxed">{pain.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── BENEFICIO — Servicios / Planes ── */}
      <section className="space-y-4 mb-10">
        <div className="text-center space-y-1">
          <p className="text-xs text-slate-500 uppercase tracking-widest font-semibold">La solución</p>
          <h2 className="text-lg font-black text-white">
            {audience === "individual" ? "Tres pasos para blindar tu negocio" : "Soluciones B2B para riesgo digital real"}
          </h2>
        </div>

        {audience === "individual" ? (
          <div className="space-y-3">
            {INDIVIDUAL_PLANS.map((plan) => (
              <div
                key={plan.id}
                className={cn(
                  "rounded-2xl p-5 border space-y-3 relative overflow-hidden",
                  plan.highlight
                    ? "border-[#FFD400]/40 bg-[#FFD400]/5"
                    : "glass-card border-slate-700/50"
                )}
              >
                {plan.badge && (
                  <div className="absolute top-0 right-0 bg-[#FFD400] text-[#0F2438] text-[10px] font-black px-3 py-1 rounded-bl-xl uppercase tracking-wide">
                    {plan.badge}
                  </div>
                )}
                <div className="flex items-start justify-between gap-2">
                  <div>
                    <span className={cn("font-black text-sm", plan.highlight ? "text-[#FFD400]" : "text-slate-300")}>
                      {plan.label}
                    </span>
                    <p className="text-[10px] text-slate-500 uppercase font-semibold mt-0.5">{plan.priceNote}</p>
                  </div>
                  <div className="text-right">
                    <span className={cn(
                      "font-black leading-none",
                      plan.highlight
                        ? "text-4xl text-[#FFD400]"
                        : plan.price === "Gratis"
                        ? "text-2xl text-green-400"
                        : "text-3xl text-white"
                    )}>{plan.price}</span>
                  </div>
                </div>
                <ul className="space-y-1.5">
                  {plan.items.map((item) => (
                    <li key={item} className="flex items-start gap-2 text-sm text-slate-300">
                      <CheckCircle className="w-3.5 h-3.5 text-[#FFD400] shrink-0 mt-0.5" />
                      {item}
                    </li>
                  ))}
                </ul>
                <a
                  href={plan.href}
                  target="_blank"
                  rel="noopener noreferrer"
                  className={cn(
                    "block w-full text-center py-3 rounded-xl text-sm font-bold transition-colors",
                    plan.highlight
                      ? "bg-[#FFD400] text-[#0F2438] hover:bg-[#FFE033] cta-shimmer"
                      : plan.price === "Gratis"
                      ? "border border-[#FFD400]/40 text-[#FFD400] hover:bg-[#FFD400]/10"
                      : "border border-slate-600 text-slate-300 hover:border-slate-400 hover:text-white"
                  )}
                >
                  {plan.cta}
                </a>
              </div>
            ))}
          </div>
        ) : (
          <div className="space-y-3">
            {MARCA_SERVICES.map((svc) => (
              <div
                key={svc.title}
                className="glass-card rounded-xl p-4 border border-slate-700/50 hover:border-slate-600 transition-colors relative"
              >
                {svc.badge && (
                  <span className="absolute top-3 right-3 bg-[#FFD400]/15 border border-[#FFD400]/30 text-[#FFD400] text-[9px] font-black px-2 py-0.5 rounded-full uppercase">
                    {svc.badge}
                  </span>
                )}
                <div className="flex items-start gap-3">
                  <div className="p-2 bg-[#FFD400]/10 rounded-lg shrink-0">
                    <span className="text-[#FFD400]">{svc.icon}</span>
                  </div>
                  <div>
                    <p className="font-bold text-sm text-white">{svc.title}</p>
                    <p className="text-xs text-slate-400 mt-1 leading-relaxed">{svc.desc}</p>
                  </div>
                </div>
              </div>
            ))}
            <p className="text-center text-xs text-slate-500 pt-1">
              No es sólo configuración: es tranquilidad, control y prevención.
            </p>
          </div>
        )}
      </section>

      {/* ── PROCESO — Pipeline visual ── */}
      <section className="space-y-4 mb-10">
        <div className="text-center space-y-1">
          <p className="text-xs text-slate-500 uppercase tracking-widest font-semibold">El proceso</p>
          <h2 className="text-lg font-black text-white">¿Cómo funciona?</h2>
          <p className="text-xs text-slate-400">Sin sorpresas. Estas son las etapas del camino.</p>
        </div>

        <div className="relative space-y-0">
          {/* Vertical connector line */}
          <div className="absolute left-[19px] top-6 bottom-6 w-px bg-gradient-to-b from-slate-700 via-[#FFD400]/20 to-slate-700" />

          {FUNNEL_STAGES.map((stage, i) => (
            <div key={i} className="flex items-start gap-3 py-3 relative">
              <div
                className={cn(
                  "w-10 h-10 rounded-full border-2 flex items-center justify-center shrink-0 bg-[#0F2438] font-black text-sm z-10",
                  stage.color
                )}
              >
                {stage.num}
              </div>
              <div className="pt-2 pb-1">
                <p className="font-bold text-sm text-white">{stage.title}</p>
                <p className="text-xs text-slate-400 mt-0.5 leading-relaxed">{stage.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── FAQ ── */}
      <section className="space-y-4 mb-10">
        <div className="text-center space-y-1">
          <p className="text-xs text-slate-500 uppercase tracking-widest font-semibold">Preguntas frecuentes</p>
          <h2 className="text-lg font-black text-white">Respuestas claras, sin letra pequeña</h2>
        </div>

        <div className="glass-card rounded-2xl border border-slate-700/50 overflow-hidden">
          <Accordion type="single" collapsible className="space-y-0">
            {FAQ_ITEMS.map((item, index) => (
              <AccordionItem
                key={item.question}
                value={`faq-${index}`}
                className="border-b border-slate-700/60 px-4 last:border-b-0"
              >
                <AccordionTrigger className="text-left text-sm font-semibold text-white py-4 hover:text-[#FFD400] [&>svg]:text-[#FFD400]">
                  {item.question}
                </AccordionTrigger>
                <AccordionContent className="text-sm text-slate-300 leading-relaxed pb-4">
                  {item.answer}
                </AccordionContent>
              </AccordionItem>
            ))}
          </Accordion>
        </div>
      </section>

      {/* ── CTA FINAL — Condicional por audiencia ── */}
      <section className="space-y-5 mb-10">
        <div className="text-center space-y-1">
          <p className="text-xs text-slate-500 uppercase tracking-widest font-semibold">El siguiente paso</p>
          <h2 className="text-lg font-black text-white">
            {audience === "individual"
              ? "¿Listo para descubrir tu nivel real de seguridad?"
              : "¿Hablamos? La primera reunión es gratuita."}
          </h2>
          <p className="text-sm text-slate-400">
            {audience === "individual"
              ? "Reserva tu auditoría gratuita. Sin compromiso. En 20-30 min sabes exactamente dónde estás."
              : "Cuéntame tu proyecto y te respondo en menos de 24 horas."}
          </p>
        </div>

        {audience === "individual" ? (
          <div className="space-y-3">
            <a
              href={CALENDLY_URL}
              target="_blank"
              rel="noopener noreferrer"
              className="cta-shimmer flex items-center justify-center gap-2 w-full py-4 bg-[#FFD400] hover:bg-[#FFE033] text-[#0F2438] font-black rounded-xl shadow-lg hover:shadow-[#FFD400]/30 transition-all"
            >
              Reservar Auditoría Gratis
              <ArrowRight className="w-5 h-5" />
            </a>
            <Link href="/quiz">
              <a className="flex items-center justify-center gap-2 w-full py-3 border border-slate-600 text-slate-300 hover:border-slate-400 hover:text-white font-bold rounded-xl transition-colors text-sm">
                O haz el quiz de privacidad primero
              </a>
            </Link>
          </div>
        ) : (
          <BrandContactForm />
        )}
      </section>

    </Layout>
  );
}

